public double density(final double[] vals) throws DimensionMismatchException {
    if (vals == null) {
        throw new IllegalArgumentException("Input values array cannot be null");
    }

    final int dim = getDimension();
    if (vals.length != dim) {
        throw new DimensionMismatchException(vals.length, dim);
    }

    return FastMath.pow(2 * FastMath.PI, -dim / 2.0) *
        FastMath.pow(covarianceMatrixDeterminant, -0.5) *
        getExponentTerm(vals);
}

public double density(final double[] vals) throws DimensionMismatchException {
    final int dim = getDimension();
    if (vals == null || vals.length != dim) {
        throw new DimensionMismatchException(vals == null ? 0 : vals.length, dim);
    }

    if (covarianceMatrixDeterminant <= 0) {
        throw new IllegalArgumentException("Covariance matrix determinant must be positive.");
    }

    return FastMath.pow(2 * FastMath.PI, -dim / 2.0) *
        FastMath.pow(covarianceMatrixDeterminant, -0.5) *
        getExponentTerm(vals);
}

